/**
 * <USER>
 * Retrieve the accepted languages sent by the browser, parse it and try to
 * match with the locales handled by the framework.
 * @return array An array containing the parsed locales.
 *               It can be empty if the string is not given or parsable.
 */
function get_accepted_locales(): array
{
    if (!array_key_exists($k = 'HTTP_ACCEPT_LANGUAGE', $_SERVER)) return [];

    $locales = [];
    $idx = 0;

    foreach (explode(',', $_SERVER[$k]) as $l) {
        if (!($l = trim($l))) continue;
        if (!preg_match('/^(?<l>[a-z0-9]{2,3})([_-](?<c>[a-z0-9]{2,3}))?(\s*;\s*q\s*=(?<q>[0-9.]+))?$/i', $l, $m)) continue;
        $m = (object) array_merge([ 'l' => null, 'c' => null, 'q' => 1 ], $m);
        $m->q = (float) $m->q;

        $language = $m->l ? get_language($m->l) : null;
        $country = $m->c ? get_country($m->c) : null;

        $locale = null;
        if ($language && $country) $locale = get_locale($language->code3 . '-' . $country->code3);
        if ($locale === null) $locale = get_locale($language->code3 . '-' . $language->default_country);

        $locales[] = (object) [
            'browser'  => (object) [ 'lang' => $m->l, 'country' => $m->c, 'priority' => $m->q, 'index' => $idx ],
            'language' => $language,
            'country'  => $country,
            'locale'   => $locale,
        ];
        $idx++;
    }

    usort($locales, function(object $a, object $b): int
    {
        if ($a->browser->priority > $b->browser->priority) return -1;
        if ($a->browser->priority < $b->browser->priority) return 1;
        return 0;
    });

    return $locales;
}

/**
 * <USER>
 * Returns an array containing the valid locales existing in the configuration
 * file. The locale will be constructed from the countries and the
 * languages codes, then the valid ones will be returned.
 * @param  bool  $force Force the renewing of the locales in the memory cache.
 * @return array        Configured locales.
 */
function get_app_locales(bool $force = false): array
{
    if ($locales = cfg('~' . ($ck = '@core.intl.locales'))) return $locales;

    $locales = [];
    $countries = cfg('~@intl.countries') ?: [];
    foreach (cfg('~@intl.languages') ?: [] as $l) {
        foreach ($countries as $c) {
            if (!($locale = get_locale($l['code'] . '-' . $c['code']))) continue;
            $locales[] = (object) [
                'code'          => $locale->code,
                'locale'        => $locale,
                'country'       => $country = get_country($locale->country),
                'language'      => $language = get_language($locale->lang),
                'standard_code' => $language->code2 . '_' . $country->code2,
                'full_name'     => $language->name . ' (' . $country->name . ')',
                'is_default'    => $l['default'] && $c['default'],
            ];
        }
    }

    cfg($ck, $locales);
    return $locales;
}

/**
 * <USER>
 * Returns a specific app locale. The returned locale will be one of the
 * locales defined in the configuration file.
 * @param  string      $locale Locale code.
 * @return null|object         App locale if exists.
 */
function get_app_locale(string $locale): ?object
{
    foreach (get_app_locales() as $l) if ($l->code === $locale) return $l;
    return null;
}

/**
 * <USER>
 * Get the app locales using <get_app_locales()> and returns the default one.
 * @return null|object Default app locale.
 */
function get_default_app_locale(): ?object
{
    foreach (get_app_locales() as $l) if ($l->is_default) return $l;
    return null;
}

/**
 * <USER>
 * Returns the current locale, based on:
 *   - user configured locale, stored in cookie;
 *   - first valid browser's accepted locale;
 *   - default locale.
 * @return null|object Current locale.
 */
function get_current_app_locale(): ?object
{
    if (($appLocaleName = cookie('MBL')) && ($appLocale = get_app_locale($appLocaleName))) return $appLocale;
    // Then get from <get_accepted_locales()>
    return get_default_app_locale();
}

/**
 * <USER>
 * Set current app locale in cookies.
 * @param string $locale Locale code.
 */
function set_current_app_locale(string $locale): void
{
    if (!($l = get_app_locale($locale))) return;
    cookie( name: 'MBL', value: $l->code, lifetime: 24 * 3600 * 365 );
}

/**
 * <USER>
 * Returns translation variables.
 * @return array Key-value array of variables.
 */
function get_translate_vars(): array
{
    return cfg('~@intl.translate_vars') ?: [];
}

/**
 * <USER>
 * Set translation variables, which will be applied on each string passed
 * to <t()>.
 * @param  array $vars Key-value array of variables.
 */
function set_translate_vars(array $vars): void
{
    cfg('~@intl.translate_vars', array_merge(get_translate_vars(), $vars));
}

/**
 * <USER>
 * Declare current locale in use with <t()>.
 * @param  string|null $locale Locale name.
 */
function locale(?string $locale = null): void
{
    cfg('@intl.translations_locale', $locale);
}

/**
 * <USER>
 * Returns the current locale name for translatable strings through <t()>.
 * @return string Current locale name
 */
function get_translations_locale(): string
{
    return cfg('~@intl.translations_locale') ?: cfg('~@intl.hardcoded_strings.default_locale') ?: 'eng-USA';
}

/**
 * <USER>
 * Translate a string, with an optional formatting of the string with the
 * passed variables.
 * @param  string|array $format     String to translate.
 *                                  If an array is given, this array have to be
 *                                  a numerical-keys array with 1, 2 or 3
 *                                  entries. If there is 1 entry, the format
 *                                  will be considered as non-array.
 *                                  If there is more entries, a parameter in
 *                                  $vars matching 'n', nb', 'num', 'number'
 *                                  or 'count' will be considered as a counter.
 *                                  If there is no match, the first parameter
 *                                  found will be considered.
 *                                  Then, with a 2-entries array,
 *                                  $format[0] = $format if counter is 1;
 *                                  $format[1] = $format if counter is 0 or > 1.
 *                                  With a 3-entries array:
 *                                  $format[0] = $format if counter is 0;
 *                                  $format[1] = $format if counter is 1;
 *                                  $format[2] = $format if counter is > 1.
 * @param  array|string $vars       Variables to process in string. If this is
 *                                  an associative array, the keys will be
 *                                  replaced in the string using brackets like:
 *                                  {foo} or {{foo}}. The double-bracket will
 *                                  be replaced by an escaped string.
 *                                  If string is provided, we assume $vars
 *                                  corresponds to $fromLocale.
 * @param  string|null  $fromLocale Locale to be translated to.
 * @param  string|null  $toLocale   MMMMMMM.
 * @return string                   String of the translation processed with
 *                                  the vars.
 */
function t(
    string | array $format,
    array | string $vars       = [],
    ?string        $fromLocale = null,
    ?string        $toLocale   = null,
): string
{
    if (is_string($vars)) {
        $fromLocale = $vars;
        $vars = [];
    }

    if ($fromLocale === null) $fromLocale = get_translations_locale();

    if (is_array($format)) {
        if (($nb = count($format = array_values($format))) === 0) {
            $format = '';
        } else if ($nb === 1) {
            $format = array_shift($format);
        } else {
            $count = null;
            foreach ([ 'n', 'nb', 'num', 'number', 'count' ] as $k) {
                if (!array_key_exists($k, $vars)) continue;
                $count = (int) ($vars[$k] ?: 0);
                break;
            }
            if ($count === null) {
                foreach ($vars as $k => $v) {
                    $count = (int) ($v ?: 0);
                    break;
                }
            }
            if ($count === null) $count = 0;
            if ($nb === 2) {
                if ($count === 1) $format = $format[0];
                else $format = $format[1];
            } else {
                if ($count === 0) $format = $format[0];
                else if ($count === 1) $format = $format[1];
                else $format = $format[2];
            }
        }
    }

    $str = $format;

    if (cfg('~@intl.scrap_all_translations')) store_intl_string($str);

    if (!$toLocale && ($currentAppLocale = get_current_app_locale())) $toLocale = $currentAppLocale->code;
    if ($toLocale) {
        $translations = get_translations($toLocale);
        if (array_key_exists($str, $translations)) {
            if ($translations[$str] !== '') $str = $translations[$str];
        } else if (cfg('~@intl.save_default_translation') || ($toLocale !== $fromLocale)) {
            set_translation(locale: $toLocale, format: $str, translation: '', clear: true);
        }
    }

    if ($vars && !is_assoc_array($vars)) {
        $str = vsprintf($str, $vars);
        $vars = [];
    }
    foreach (array_merge(get_translate_vars(), $vars) as $k => $v) {
        $str = str_replace('{{' . $k . '}}', esc($v), $str);
        $str = str_replace('{' . $k . '}', (string) $v, $str);
    }
    return $str;
}

/**
 * <USER>
 * Translate a string, exactly like <t>, then echo the translation.
 * @param  string|array $format String to translate.
 * @param  array        $vars   Variables to process in the string.
 *
 *
 * @param  string|array $format     String to translate.
 * @param  array|string $vars       Variables to process in string.
 *                                  If string is provided, we assume $vars
 *                                  corresponds to $fromLocale.
 * @param  string|null  $fromLocale Locale to be translated to.
 * @param  string|null  $toLocale   MMMMMMM.
 */
function _t(
    string | array $format,
    array | string $vars       = [],
    ?string        $fromLocale = null,
    ?string        $toLocale   = null,
): void
{
    echo t($format, $vars, $fromLocale, $toLocale);
}

/**
 * <USER>
 * Translate a string, exactly like <t>, escape it, then echo the translation.
 * @param  string|array $format String to translate.
 * @param  array        $vars   Variables to process in the string.
 *
 *
 * @param  string|array $format     String to translate.
 * @param  array|string $vars       Variables to process in string.
 *                                  If string is provided, we assume $vars
 *                                  corresponds to $fromLocale.
 * @param  string|null  $fromLocale Locale to be translated to.
 * @param  string|null  $toLocale   MMMMMMM.
 */
function __t(
    string | array $format,
    array | string $vars       = [],
    ?string        $fromLocale = null,
    ?string        $toLocale   = null,
): void
{
    echo esc(t($format, $vars, $fromLocale, $toLocale));
}

/**
 * <USER>
 * Load the translation file and store translations in an array.
 * @param  string $locale Locale code.
 * @param  bool   $force  Force the refresh of the memory-saved translations.
 * @return array          Array containing original text as key, and translated
 *                        text as value.
 */
function get_translations(string $locale, bool $force = false): array
{
    if ($translations = cfg('~' . ($ck = ('@core.intl.translations.' . $locale)))) return $translations;
    $translations = [];
    foreach (get_bundles() as $bundle) {
        if (!is_file($f = join_path($bundle->dir, 'intl', $locale . '.xml'))) continue;
        $xml = simplexml_load_file($f);
        foreach ($xml->str ?? [] as $str) $translations[(string) $str->o] = (string) $str->t;
    }
    cfg($ck, $translations);
    return $translations;
}

/**
 * <USER>
 * Store a translation entry in the bundle's translation file for the
 * specified locale.
 * @param string $locale      Locale code.
 * @param string $format      Original text.
 * @param string $translation Translated text.
 * @param string $bundle      Bundle name. Default is 'default'.
 * @param bool   $clear       Clear memory-saved translations for this locale.
 */
function set_translation(string $locale, string $format, string $translation, string $bundle = 'default', bool $clear = true): void
{
    if (is_env('prod')) return;

    if (!($bundle = get_bundle($bundle))) return;

    $translations = get_translations(locale: $locale, force: true);
    $translations[$format] = $translation;

    $f = join_path($bundle->dir, 'intl', $locale . '.xml');
    rmkdir(dirname($f));

    $dom = new DOMDocument('1.0', 'utf-8');
    $dom->preserveWhiteSpace = false;
    $strings = $dom->createElement('strings');
    $dom->appendChild($strings);

    foreach ($translations as $k => $v) {
        $string = $dom->createElement('str');
        $strings->appendChild($string);
        $original = $dom->createElement('o');
        $original->appendChild($dom->createTextNode($k));
        $string->appendChild($original);
        $translated = $dom->createElement('t');
        $translated->appendChild($dom->createTextNode($v));
        $string->appendChild($translated);
    }

    $xml = $dom->saveXML();
    $xml = str_replace('<str>', "\n  <str>", $xml);
    $xml = str_replace('</strings>', "\n</strings>", $xml);
    file_put_contents($f, $xml);

    if ($clear) cfg('@core.intl.translations.' . $locale, null);
}

/**
 * Sotre an internationalizable string, in a simple XML file.
 * @param  string $str Translatable string.
 */
function store_intl_string(string $str): void
{
    if (!is_env('dev')) return;

    $path = get_data_dir('intl', 'scrap.xml');

    $dom = new DOMDocument('1.0', 'utf-8');
    $dom->preserveWhiteSpace = false;
    $dom->formatOutput = true;
    $strings = null;

    if (is_file($path)) {
        $dom->load($path);
        $strings = $dom->getElementsByTagName('strings')[0];
    } else {
        $strings = $dom->createElement('strings');
        $dom->appendChild($strings);
    }

    foreach ($strings->getElementsByTagName('str') as $s) {
        if ($s->nodeValue === $str) return;
    }

    $string = $dom->createElement('str');
    $string->appendChild($dom->createTextNode($str));
    $strings->appendChild($string);

    rmkdir(dirname($path));
    $dom->save($path);
}

