    ];

    foreach ($countries as $code3 => $country) {
        $countries[$code3]->sanitized_name = remove_accents($country->name);
    }

    uasort($countries, function(object $a, object $b): int
    {
        if (($aa = strtolower($a->sanitized_name)) < ($bb = strtolower($b->sanitized_name))) return -1;
        return $aa > $bb ? 1 : 0;
    });

    return $countries;
}

/**
 * <USER>
 * Retrieve info about a specific country.
 * @param  object|string $code Country object or code, with 2 (ISO 639-1)
 *                             or 3 (ISO 639-2) character.
 * @return object|null         Corresponding country, or null if the code
 *                             was not found.
 */
function get_country(object | string $country): ?object
{
    if (is_object($country)) return $country;
    $all = get_countries();
    if (strlen($country) === 3) {
        if (!array_key_exists($country, $all)) return null;
        return $all[$country];
    }

    foreach ($all as $c) if ($c->code2 === $country) return $c;
    return null;
}

/**
 * <USER>
 * Returns the regex which can be used to validate a postcode.
 * It will be a simple regex compatible with all countries.
 * @return string Postcode regular expression.
 */
function get_default_postcode_regex(): string
{
    return "[a-z0-9][a-z0-9- ]{0,10}[a-z0-9]";
}

/**
 * <USER>
 * Check if a postcode is valid. If country is provided
 * @param  mixed              $postcode Postcode to validate.
 * @param  object|string|null $country  Country object or code. If null, the
 *                                      default postcode regex will be used.
 * @return boolean                      Is valid or not?
 */
function is_postcode_valid(mixed $postcode, object | string | null $country = null): bool
{
    if ($country !== null && !($country = get_country($country))) throw new Microbe_Exception("Invalid country while trying to validate postcode");
    if (!is_scalar($postcode)) return false;
    return (bool) preg_match('/^' . ($country->postcode ?: get_default_postcode_regex()) . '$/i', (string) $postcode);
}

/**
 * <USER>
 * Cast a given value to a phone number. If the value is not readable, null
 * will be returned.
 * @param  mixed       $number      Input phone number.
 * @param  string|int  $dialingCode Prefix automatically a dialing code.
 * @return string|null              Phone number formatted, or null if
 *                                  invalid format.
 */
function cast_phone_number(mixed $number, string | int | null $dialingCode = null): ?string
{
    if (!is_scalar($number)) return null;
    $number = preg_replace('/[^\d+-]/', '', (string) $number);

    if ($dialingCode = preg_replace('/[^\d-]/', '', (string) $dialingCode)) {
        if (str_starts_with($number, $dialingCode)) $number = substr($number, strlen($dialingCode));
        $number = str_replace('-', '', $number);
        $dialingCode = '+' . $dialingCode;
    }

    if (strlen($number) < 5) return null;
    return ($dialingCode ?: '') . $number;
}

/**
 * <USER>
 * User the phone casting function to check if the phone number is valid.
 * @param  mixed $number Input phone number.
 * @return bool  Is phone valid?
 */
function is_valid_phone_number(mixed $number): bool
{
    return cast_phone_number($number) !== null;
}

/**
 * <USER>
 * Check if a given value is a valid postcode and clean it.
 * @param  mixed       $postcode Possibily a postcode.
 * @return string|null           Cleaned postcode if the given value is
 *                               acceptable.
 */
function cast_postcode(mixed $postcode): ?string
{
    if (!$postcode || !is_scalar($postcode)) return null;
    return preg_replace('/[^A-Z0-9]+/', '', strtoupper((string) $postcode)) ?: null;
}

