/**
 * <USER>
 * Retrieve info about a specific language.
 * @param  string      $code Country code, with 2 (ISO 639-1)
 *                           or 3 (ISO 639-2) character.
 * @return object|null       Corresponding language, or null if the code
 *                           was not found.
 */
function get_language(string $code): ?object
{
    $all = get_languages();
    if (strlen($code) === 3) {
        if (!array_key_exists($code, $all)) return null;
        return $all[$code];
    }

    foreach ($all as $c) if ($c->code2 === $code) return $c;
    return null;
}

/**
 * <USER>
 * Retrieve all the possible languages combinations, aka lang mixed with
 * countries where it can be spoken.
 * @return array Array of the mixed languages/countries.
 */
function get_locales(): array
{
    $locales = [];
    foreach (get_languages() as $l) {
        foreach ($l->countries as $c) {
            $locales[$code = ($l->code3 . '-' . $c)] = (object) [
                'code'         => $code,
                'lang_name'    => $l->name,
                'country_name' => ($countryName = get_country($c)->name),
                'full_name'    => $l->name . ' (' . $countryName . ')',
                'lang'         => $l->code3,
                'country'      => $c,
            ];
        }
    }
    return $locales;
}

/**
 * <USER>
 * Get a specific locale, based on its code (aka xxx-XXX).
 * @param  string      $code Locale code.
 * @return object|null       Locale object if found. Else, null.
 */
function get_locale(string $code): ?object
{
    $all = get_locales();
    if (!array_key_exists($code, $all)) return null;
    return $all[$code];
}

