listen('before_first_render', function(): void
{
    set_template_vars([
        'app_locales'              => $appLocales = get_app_locales(),
        'has_multiple_app_locales' => $appLocales > 1,
        'default_app_locale'       => get_default_app_locale(),
        'current_app_locale'       => get_current_app_locale(),
    ]);
});

